#include<bits/stdc++.h>
using namespace std;
int n,q,p;
int a[1000010],b[1000010];
struct segment_tree
{
    struct node
    {
        int sum;
        int lson,rson;
    }a[2000010];
    int cnt;
    segment_tree():cnt(0){}
    void pushup(int x)
    {
        a[x].sum=(a[a[x].lson].sum|a[a[x].rson].sum);
    }
    int init(int l,int r)
    {
        int x=++cnt,mid=(l+r)>>1;
        if(l==r)
        {
            a[x].sum=0;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(int x,int l,int r,int p,int z)
    {
        if(l>p||r<p)
        {
            return;
        }
        if(l==r)
        {
            a[x].sum=z;
            return;
        }
        int mid=(l+r)>>1;
        update(a[x].lson,l,mid,p,z);
        update(a[x].rson,mid+1,r,p,z);
        pushup(x);
    }
    int query(int x,int l,int r,int v)
    {
        if(l==r)
        {
            if((v|a[x].sum)<=p)
            {
                return -1;
            }
            return l;
        }
        int mid=(l+r)>>1;
        if((v|a[a[x].lson].sum)>p)
        {
            return query(a[x].lson,l,mid,v);
        }
        else
        {
            return query(a[x].rson,mid+1,r,v|a[a[x].lson].sum);
        }
    }
}t;
vector<pair<int,int>> v[1000010];
int main()
{
    scanf("%d%d%d",&n,&q,&p);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=q;i++)
    {
        int l,r,x;
        scanf("%d%d%d",&l,&r,&x);
        b[i]=x;
        v[l].push_back({i,b[i]});
        v[r+1].push_back({i,0});
    }
    t.init(1,q);
    for(int i=1;i<=n;i++)
    {
        for(auto j:v[i])
        {
            t.update(1,1,q,j.first,j.second);
        }
        printf("%d ",t.query(1,1,q,a[i]));
    }
    return 0;
}
